import {Socket} from 'net'
import {ExecuteReqeustError} from './execute-request'
import {AddressInfo} from './utils'

/**
 * Types for the HTTP CONNECT upstream execution path.
 *
 * CLIENT-SIDE API. Intended for SOCKS5 servers running inside a tunnel agent
 * on a customer machine (e.g. `@applitools/execution-grid-tunnel`) whose
 * destinations are reachable only through a corporate HTTP CONNECT proxy.
 *
 * This is INTENTIONALLY separate from the `proxyServers` / `getAvailableProxy`
 * API (see `./execute-request-through-remote-proxy.d.ts`), which is for
 * SERVER-SIDE SOCKS5-chain load-balancing inside the EC browser pod
 * (`@applitools/eg-chromedriver-image`). Both APIs may be configured on the
 * same `SocksServer`; the HTTP-CONNECT branch is consulted first per request
 * and falls through to the SOCKS5-chain branch when the resolver returns
 * `null`/`undefined`.
 */

export interface HttpProxyDecision {
  /** Hostname or IP of the upstream HTTP CONNECT proxy. */
  address: string
  /** TCP port of the upstream HTTP CONNECT proxy. */
  port: number
  /**
   * If `true`, speak TLS to the proxy (corresponds to PAC's `HTTPS host:port`
   * directive). The HTTP CONNECT exchange runs inside the TLS tunnel so the
   * `Proxy-Authorization` header is encrypted in transit. The proxy is
   * verified against the host's default trust anchors; mTLS / custom CAs
   * are out of scope here.
   *
   * Defaults to `false` (plain TCP — PAC's `PROXY host:port`).
   */
  tls?: boolean
  /**
   * Optional credentials for `Proxy-Authorization: Basic`.
   * Either a `"user:pass"` string or a `{username, password}` object.
   */
  auth?: string | {username: string; password: string}
}

/**
 * One entry in a proxy chain returned by the resolver.
 *
 * - An {@link HttpProxyDecision} means "try this proxy".
 * - `'DIRECT'` is the sentinel for PAC's `DIRECT` directive — open a direct
 *   socket to the destination if reached during chain iteration. Typically
 *   the last entry in a chain like `PROXY a:1; PROXY b:2; DIRECT`.
 */
export type ProxyChainEntry = HttpProxyDecision | 'DIRECT'

export interface HttpProxyResolverContext {
  socket: Socket
  destinationInfo: AddressInfo
  originInfo: AddressInfo
}

/**
 * Resolver result shapes:
 *
 * - `null` / `undefined` — no decision; the dispatcher falls through to the
 *   existing SOCKS5-chain branch (or DIRECT if that is unconfigured).
 * - {@link HttpProxyDecision} — single proxy; equivalent to a one-element
 *   chain `[decision]`.
 * - {@link ProxyChainEntry}[] — ordered chain. Each entry is tried in order;
 *   on retryable failure (TCP failure, proxy 5xx, malformed response), the
 *   next entry is tried. `407` (auth) is **not** retried (auth was specific
 *   to that proxy). The `DIRECT` sentinel, if present, opens a direct
 *   socket to the destination. An empty array `[]` falls through like `null`.
 */
export type HttpProxyResolverResult =
  | HttpProxyDecision
  | ProxyChainEntry[]
  | null
  | undefined

export type HttpProxyResolver = (
  context: HttpProxyResolverContext,
) => Promise<HttpProxyResolverResult> | HttpProxyResolverResult

export interface ExecuteRequestThroughHttpProxyParameters {
  originalSocket: Socket
  proxy: HttpProxyDecision
  addressType: number
  address: string
  port: number
  requestBuffer: Buffer
  /** Called once the proxy returned an HTTP status line. */
  onProxyResponded: (statusCode: number) => void
  /** Called when the proxy refused or errored before the tunnel was established. */
  onProxyFailed: (rfc1928Reply: number) => void
  end: (rfc1928Reply: number, args: {requestBuffer: Buffer}) => void
  onError: (error: ExecuteReqeustError) => void
  /** Called when TCP to the proxy is established (before CONNECT is sent). */
  onConnect: (destination: Socket) => void
}
